import{_ as e,o as r,c as o,a2 as t}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"G01: 公司歷史與創辦人研究 - 經營審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/2492_華新科/20260512/G01_公司歷史與創辦人研究.md","filePath":"審計報告庫/經營審計/2492_華新科/20260512/G01_公司歷史與創辦人研究.md"}'),l={name:"審計報告庫/經營審計/2492_華新科/20260512/G01_公司歷史與創辦人研究.md"};function i(n,a,h,s,d,_){return r(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="g01-公司歷史與創辦人研究-經營審計專家報告" tabindex="-1">G01: 公司歷史與創辦人研究 - 經營審計專家報告 <a class="header-anchor" href="#g01-公司歷史與創辦人研究-經營審計專家報告" aria-label="Permalink to &quot;G01: 公司歷史與創辦人研究 - 經營審計專家報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>公司歷史背景、創辦人及其性格與價值觀為何？對公司目前文化及發展策略有何深層影響？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：華新科由焦廷標家族於1992年收購萬邦電子後轉型被動元件，焦佑衡掌舵34年，以「穩健併購、誠信供貨、內部整合」為核心價值，正處於創二代交棒專業經理人之轉折點。</li><li><strong>風險評級</strong>：低至中</li><li><strong>數據時效</strong>：截至2026年5月12日最新公開資料</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>A-（良）</strong>：華新科源自1970年萬邦電子，1992年改組為被動元件廠。創辦人家族意志透過焦佑衡34年領導深植，經營哲學「做小不如做好」貫穿決策。2025營收364.6億、EPS 4.74元年減23%；2026年4月營收37.05億創近年新高，AI動能發酵中。扣分項：交班僅3年，新任總經理資歷尚淺；過去高度依賴消費電子，轉型高階市場成效待驗證。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-創辦人畫像與家族背景" tabindex="-1">1. 創辦人畫像與家族背景 <a class="header-anchor" href="#_1-創辦人畫像與家族背景" aria-label="Permalink to &quot;1. 創辦人畫像與家族背景&quot;">​</a></h3><p>華新科創辦人源自焦廷標（1924-2018），其三子焦佑衡1992年從父親手中購入萬邦電子後自行創業。焦佑衡性格：低調務實、重視誠信合約、善於在日本廠商挖掘技術價值，對外稱「不想做最大，想做最好」。</p><p>焦佑衡34年掌舵，1992年購入萬邦改名華新科，2000年併購Kamaya掌握車規電阻技術，2005年與信昌電策略結盟。此三步奠定了華新科「從原料到通路」垂直整合的根基。</p><h3 id="_2-企業文化核心基因" tabindex="-1">2. 企業文化核心基因 <a class="header-anchor" href="#_2-企業文化核心基因" aria-label="Permalink to &quot;2. 企業文化核心基因&quot;">​</a></h3><p>文化底色為「系統化+垂直整合+誠信供貨」。三大支柱：PSA平台——信昌電掌控陶瓷粉末、Kamaya掌控電阻技術，從原料到通路垂直整合；制度化管理——自2001年起每年投入營收3%研發，全球11廠6研發中心50家分銷；誠信供貨——2018-2019缺貨潮堅持合約價，建立長期客戶信任。</p><h3 id="_3-接班進程與治理韌性" tabindex="-1">3. 接班進程與治理韌性 <a class="header-anchor" href="#_3-接班進程與治理韌性" aria-label="Permalink to &quot;3. 接班進程與治理韌性&quot;">​</a></h3><p>2023年6月啟動總經理輪調，焦佑衡卸任，由佳邦原總經理曾明燦接任。2025年股東會宣告轉型「好的投資者」，專注宏觀戰略。董事會任期2025-2028年，家族仍主導但管理層已交棒40-50歲專業經理人。關鍵人風險：焦佑衡若淡出，PSA平台協調能力可能弱化。</p><h3 id="_4-2025-2026經營成果" tabindex="-1">4. 2025-2026經營成果 <a class="header-anchor" href="#_4-2025-2026經營成果" aria-label="Permalink to &quot;4. 2025-2026經營成果&quot;">​</a></h3><p>2025營收364.6億（YoY+4.9%）、GM 17.3%、EPS 4.74元（年減23%）。2026動能轉強：1-4月累計營收132.7億（YoY+15.8%），4月37.05億創新高（YoY+16%）。AI營收約10%，預估2026年翻倍。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>接班風險仍在發酵期</strong>：2023啟動交班僅3年，新任總經理曾明燦2023年6月才接任，尚無獨立穿越景氣循環的紀錄。焦佑衡若加速淡出，PSA十家公司平台協調機制可能鬆散。</li><li><strong>消費電子依賴歷史包袱</strong>：華新科過去高度依賴PC/NB/手機等消費電子，2022-2024庫存調整期（2023Q4 EPS僅1.55低點）暴露其景氣循環特性。轉型AI/車用雖有進展但基礎佔比仍低（AI約10%、車用尚在起步）。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>垂直整合壁壘持續強化</strong>：透過信昌電掌握陶瓷粉末、Kamaya掌握高階電阻技術，原料自主比例優於同業國巨。2026年初集團旗下久尹漲價（熱敏/壓敏電阻），反映上游成本轉嫁能力。</li><li><strong>成長動能明確轉向高階</strong>：2026年1-4月營收累計YoY+15.8%較2025全年+4.91%明顯加速，主因AI伺服器高壓MLCC出貨成長。毛利率優勢（AI產品高出均10個百分點）有望帶動2026三率三升。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>華新科擁有36年被動元件產業底蘊與垂直整合護城河，創辦家族意志穩健傳承中；但交班僅三年、管理層洗牌仍在磨合期，2026-2027年是否出現經營斷層為核心觀察點。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>web_search</strong>：華新科 2492 歷史沿革 創辦人 焦廷標 （多家綜合來源）</li><li><strong>web_search</strong>：華新科 焦佑衡 經營理念 企業文化 接班計畫 （天下雜誌/鉅亨網/經濟日報多篇）</li><li><strong>web_search</strong>：華新科 2025年 營收 EPS 財報（公開資訊）</li><li><strong>FinMind</strong>：TaiwanStockMonthRevenue（stock_id=2492, 2025-01-01 ~ 2026-05-12）</li><li><strong>年報PDF</strong>：2024 Q4合併財報（公司沿革第16頁）</li></ul>',27)])])}const b=e(l,[["render",i]]);export{u as __pageData,b as default};
